I'm about to implement a new read endpoint in the Inbox feature: GetActiveCustomersForOrder — given an OrderId it returns the customers that may be assigned to that order (active relationship with the order's vendor). Here's my draft handler in Sales/Acme.Sales.Application/Features/Inbox/:

```csharp
public class GetActiveCustomersForOrder
{
    public record Query(Guid OrderId) : IRequest<IReadOnlyList<CustomerVm>>;
    public record CustomerVm(Guid Id, string Name);

    public class Handler(IAppDbContext dbContext) : IRequestHandler<Query, IReadOnlyList<CustomerVm>>
    {
        public async Task<IReadOnlyList<CustomerVm>> Handle(Query request, CancellationToken cancellationToken)
        {
            var order = await dbContext.Orders
                .Include(o => o.Vendor)
                .FirstOrDefaultAsync(o => o.Id == request.OrderId, cancellationToken);
            var customers = await dbContext.Customers.ToListAsync(cancellationToken);
            var result = customers
                .Where(c => dbContext.VendorCustomerRelationships.Any(vcr =>
                    vcr.VendorId == order.Vendor.Id && vcr.CustomerId == c.Id
                    && !vcr.IsDeleted && vcr.StartDate <= DateOnly.FromDateTime(DateTime.Today)
                    && (vcr.EndDate == null || vcr.EndDate >= DateOnly.FromDateTime(DateTime.Today))))
                .Select(c => new CustomerVm(c.Id, c.Name))
                .ToList();
            return result;
        }
    }
}
```

